package main
import("bufio";"fmt";"os")
type item struct{value,freq,time int}
func run(capacity int, ops [][]int, kinds []byte)string{clock:=0;cache:=map[int]item{};res:=[]string{};for i,op:=range ops{clock++;switch kinds[i]{case 'C':cache=map[int]item{};res=append(res,"null");case 'P':key,val:=op[0],op[1];if capacity==0{res=append(res,"null");continue};if it,ok:=cache[key];ok{cache[key]=item{val,it.freq+1,clock}}else{if len(cache)==capacity{victimKey,victim:=0,item{0,1<<30,1<<30};first:=true;for k,it:=range cache{if first||it.freq<victim.freq||it.freq==victim.freq&&(it.time<victim.time||it.time==victim.time&&k<victimKey){victimKey,victim,first=k,it,false}};delete(cache,victimKey)};cache[key]=item{val,1,clock}};res=append(res,"null");case 'G':key:=op[0];if it,ok:=cache[key];ok{cache[key]=item{it.value,it.freq+1,clock};res=append(res,fmt.Sprint(it.value))}else{res=append(res,"-1")}}};out:="[";for i,s:=range res{if i>0{out+=","};out+=s};return out+"]"}
func main(){in:=bufio.NewReader(os.Stdin);out:=bufio.NewWriter(os.Stdout);defer out.Flush();var t int;if _,e:=fmt.Fscan(in,&t);e!=nil{return};for tc:=0;tc<t;tc++{var cap,m int;fmt.Fscan(in,&cap,&m);ops:=make([][]int,m);kinds:=make([]byte,m);for i:=0;i<m;i++{var op string;fmt.Fscan(in,&op);kinds[i]=op[0];if op=="C"{ops[i]=[]int{}}else if op=="P"{var a,b int;fmt.Fscan(in,&a,&b);ops[i]=[]int{a,b}}else{var a int;fmt.Fscan(in,&a);ops[i]=[]int{a}}};if tc>0{fmt.Fprintln(out);fmt.Fprintln(out)};fmt.Fprint(out,run(cap,ops,kinds))}}
